(window.webpackJsonp=window.webpackJsonp||[]).push([[94],{320:function(n,t,e){"use strict";e.r(t);var s=e(8),r=Object(s.a)({},(function(){var n=this,t=n.$createElement,e=n._self._c||t;return e("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[e("h1",{attrs:{id:"又来到温州这个地方"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#又来到温州这个地方"}},[n._v("#")]),n._v(" 又来到温州这个地方")]),n._v(" "),e("p",[n._v("从杭州到温州，天堂到地狱一般的旅程。当在杭州待过，再来看温州，不得不说，我真的不喜欢这个地方。\n虽然在杭州只是呆了两天，但杭州带给我的感动远远多于在温州的这半年。这不是对温州的偏见。\n包括走的那天，杭州4路程的司机给我留下了很深刻的影响。她会很关切地提醒她的乘客站好，避免摔倒。\n这是我第一次看到，原来公交车内还可能有这样的温暖场面。")]),n._v(" "),e("p",[n._v("对于上学，我没有一点期待，感觉就是一个累。想到要做的东西，我提不起什么劲。\n感觉活在仓促当中，每天都在赶进度，我的内心是矛盾的。越来越觉得我不想这样，我心很累。\n我的投入和产出不成比例，花了那么多的时间，得到的东西确是那么少。\n拿那么一点点工资，做这么多事，占用了我所有的业余时间，对于这一点我感觉很不好。\n重点是每天心里面都很慌张，完全没有办法让自己平静下来。")]),n._v(" "),e("p",[n._v("还说自己要做自媒体，感觉被这些东西搞得心里面好乱。\n所有的东西，包括六级成绩过了也不能够带给我一点快乐的感觉，好像这些都是理所当然。SHIT。\n要说这两年我真的开心吗? 我他妈真的不开心。奶奶去世过后我他妈就没有再真正感觉到开心了。\nFUCK。 我还想要为奶奶写下一本书呢。")])])}),[],!1,null,null,null);t.default=r.exports}}]);